// Determine nurture sequence based on lead data
const payload = $input.first().json.payload;
const event_type = $input.first().json.event_type;

let sequenceType = 'general';
let delayDays = 1;

// Select sequence based on insurance type
const insuranceTypes = payload.insurance_types || [];
if (insuranceTypes.includes('commercial') || insuranceTypes.includes('business')) {
  sequenceType = 'commercial';
  delayDays = 2; // Longer cycle for commercial
} else if (insuranceTypes.includes('auto')) {
  sequenceType = 'auto';
} else if (insuranceTypes.includes('home') || insuranceTypes.includes('homeowners')) {
  sequenceType = 'home';
} else if (insuranceTypes.includes('life')) {
  sequenceType = 'life';
  delayDays = 3; // Life insurance needs more nurturing
}

// Adjust based on status change
if (event_type === 'lead.status_changed') {
  if (payload.new_status === 'nurturing') {
    delayDays = 0; // Start immediately
  }
}

return {
  lead_id: $input.first().json.entity_id,
  agency_workspace_id: $input.first().json.agency_workspace_id,
  sequence_type: sequenceType,
  delay_days: delayDays,
  email: payload.email,
  first_name: payload.first_name || 'there'
};
